-- IJP apply: normalized_export.json -> equipment matching 'electrostatic precipatator'
-- 2 plans; replaces existing activities on matched equipment.

-- 1) remove existing activities on matched equipment (tasks cascade)
delete from public.inspection_activities a
using public.equipment_parts ep, public.equipment e
where a.equipment_part_id = ep.equipment_part_id
  and ep.equipment_id = e.equipment_id and e.equipment_code in ('BP-001', 'BP-007');

-- 2) insert IJP plan activities for every matched equipment
with plan(pcode, suffix, cat, freq, custom_days, prio, role, instructions, checklist) as (values
  ('FLMRIELE11', 'outer components of the Electrostatic precipatator (1 month)', 'Wear', 'Monthly', null, 'Medium', 'Mechanical Engineer', 'This inspection is carried out to : inspect all the outer components of the Electrostatic precipatator based on visual checks and other simple controls while it is under normal operating condition.', '[{"label": "Safety: Check condition of access, guardrails, housings, ladders, emergency stops."}, {"label": "Safety: Check lighting."}, {"label": "Safety: Check protections moving parts."}, {"label": "Environment: Cleaning of the equipement and around."}, {"label": "Environment: Condition of dust emission."}, {"label": "Casing: Check the abnormal noise."}, {"label": "Casing: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Casing: Check for any leakage or falls air."}, {"label": "Casing: Check the condition of insulation."}, {"label": "Inlet cone and inlet hot gas duct: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Inlet cone and inlet hot gas duct: Check for any leakage or falls air."}, {"label": "Inlet cone and inlet hot gas duct: Check the condition of insulation."}, {"label": "Rapping systems: Lower Geared Motor for inlet screen"}, {"label": "Rapping systems: Check Gear box temperature."}, {"label": "Rapping systems: Check the abnormal sounds."}, {"label": "Rapping systems: Check for any oil leakage."}, {"label": "Rapping systems: Check gear box condition and mounting."}, {"label": "Rapping systems: Upper Geared Motor for inlet screen"}, {"label": "Rapping systems: Check Gear box temperature."}, {"label": "Rapping systems: Check the abnormal sounds."}, {"label": "Rapping systems: Check for any oil leakage."}, {"label": "Rapping systems: Check gear box condition and mounting."}, {"label": "Rapping systems: rapping gearmotor for collecting plate of 1st chamber"}, {"label": "Rapping systems: Check Gear box temperature."}, {"label": "Rapping systems: Check the abnormal sounds."}, {"label": "Rapping systems: Check for any oil leakage."}, {"label": "Rapping systems: Check gear box condition and mounting."}, {"label": "Rapping system for discharge electrod: Geared Motor."}, {"label": "Rapping system for discharge electrod: Check Gear box temperature."}, {"label": "Rapping system for discharge electrod: Check the abnormal sounds."}, {"label": "Rapping system for discharge electrod: Check for any oil leakage."}, {"label": "Rapping system for discharge electrod: Check gear box condition and mounting."}, {"label": "Rapping system for discharge electrod: Coupling."}, {"label": "Rapping system for discharge electrod: Check for abnormal noise."}, {"label": "Rapping system for discharge electrod: Check the cover fixation of all the Mechanism."}, {"label": "Rapping system for discharge electrod: Mechanism."}, {"label": "Rapping system for discharge electrod: Check the flanged roller ( bolt missed, bearing defect, wear)."}, {"label": "Rapping system for discharge electrod: Check the CAM (wear,deformation,cracks)."}, {"label": "Rapping system for discharge electrod: Check the CAM shaft (wear, cracks, deformation)."}, {"label": "Rapping system for discharge electrod: Check the Pedestal bearing."}, {"label": "Rapping system for discharge electrod: Check the Rollet that move over the CAM (bearing defect, missed)."}, {"label": "Rapping system for discharge electrod: Check the release element (wear, bolt , Loss)."}, {"label": "Rapping system for discharge electrod: Check the Needle bearing(defect greaseing)."}, {"label": "Rapping system for discharge electrod: Check the Lifting element (thread wear, loss)."}, {"label": "Rapping system for discharge electrod: Check overall the greasing condition of the mechanism."}, {"label": "Casing: Check the abnormal noise."}, {"label": "Casing: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Casing: Check for any leakage or falls air."}, {"label": "Casing: Check