  ('FLMRIELE11-2', 'internal components of the Electrostatic precipatator (6 month)', 'Wear', 'Semi-Annual', null, 'Medium', 'Mechanical Engineer', 'This inspection is carried out to : inspect all the internal components of the Electrostatic precipatator based on visual checks and other simple controls while it is under stoppage condition.', '[{"label": "Safety: Check condition of access, guardrails, housings, ladders, emergency stops."}, {"label": "Safety: Check lighting."}, {"label": "Safety: Check protections moving parts."}, {"label": "Environment: Cleaning of the equipement and around."}, {"label": "Environment: Condition of dust emission."}, {"label": "Casing: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Casing: Check the condition of insulation."}, {"label": "Inlet cone and inlet hot gas duct: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Inlet cone and inlet hot gas duct: Check the condition of insulation."}, {"label": "Inlet cone and inlet hot gas duct: Check the condition duct deflectors"}, {"label": "Inlet screen: Check inlet screen deflectors (missed, deformed, worn out,….. Etc.)"}, {"label": "Inlet screen: Check upper raping system hammers&anvils (missed, deformed, loose bolts, ….)"}, {"label": "Inlet screen: Check lower raping system hammers&anvils (missed, deformed, loose bolts, ….)"}, {"label": "Casing: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Casing: Check the condition of insulation."}, {"label": "Discharge and collecting plates: Ceck colecting plates (worn out, corrosion, move out from its guide, …..)"}, {"label": "Discharge and collecting plates: Check discharge electorde condition (cut, contacted with collecting plates)"}, {"label": "Discharge and collecting plates: Check space between collecting plates and discharge electrode"}, {"label": "Rapping system for collecting plates: Check all hammers condition (missed, deformed, worn out push, ……)"}, {"label": "Rapping system for collecting plates: Check all anvils condition (missed, cracked, broken, deformed, ……..)"}, {"label": "Rapping system for collecting plates: Check cond. of system (hammers shifted on anvils, raping shaft condition …)"}, {"label": "Rapping system for discharge electrod: Check all hammers condition (missed, deformed, worn out push, ……)"}, {"label": "Rapping system for discharge electrod: Check all anvils condition (missed, cracked, broken, deformed, ……..)"}, {"label": "Rapping system for discharge electrod: Check cond. of system (hammers shifted on anvils, raping shaft condition …)"}, {"label": "Casing: Check casing condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Casing: Check the condition of insulation."}, {"label": "Discharge and collecting plates: Ceck colecting plates (worn out, corrosion, move out from its guide, …..)"}, {"label": "Discharge and collecting plates: Check discharge electorde condition (cut, contacted with collecting plates)"}, {"label": "Discharge and collecting plates: Check space between collecting plates and discharge electrode"}, {"label": "Rapping system for collecting plates: Check all hammers condition (missed, deformed, worn out push, ……)"}, {"label": "Rapping system for collecting plates: Check all anvils condition (missed, cracked, broken, deformed, ……..)"}, {"label": "Rapping system for collecting plates: Check the ( wheels , chain , insulator shafts)"}, {"label": "Rapping system for collecting plates: Check cond. of system (hammers shifted on anvils, raping shaft condition …)"}, {"label": "Rapping system for discharge electrod: Check all hammers condition (missed, deformed, worn out push, ……)"}, {"label": "Rapping system for discharge electrod: Check all anvils condition (missed, cracked, broken, deformed, ……..)"}, {"label": "Rapping system for discharge electrod: Check the ( wheels , chain , insulator shafts)"}, {"label": "Rapping system for discharge electrod: Check cond. of system (hammers shifted on anvils, raping shaft condition …)"}, {"label": "Roof beams: Check 1st beam condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Roof beams: Check 2nd beam condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Roof beams: Check 2rd beam condition (holes, deformation, corrosion, wear , cracks…)."}, {"label": "Explosion doors: Chech condition of explosion doors (holes, corrosion, wear, cracks …...)."}]'::jsonb)
)
insert into public.inspection_activities
  (equipment_part_id, activity_code, activity_name, inspection_category,
   frequency_type, custom_interval_days, priority, responsible_role,
   instructions, standard_checklist)
select ep.equipment_part_id,
       e.equipment_code || '-' || pl.pcode,
       e.equipment_name || ' — ' || pl.suffix,
       pl.cat::public.inspection_category, pl.freq::public.frequency_type,
       pl.custom_days::integer, pl.prio::public.priority_level,
       pl.role::public.app_user_role, nullif(pl.instructions,''), pl.checklist
from plan pl
cross join public.equipment e
join public.equipment_parts ep on ep.equipment_id = e.equipment_id and ep.part_code = 'MAIN'
where e.equipment_code in ('BP-001', 'BP-007');
